import{_ as t,o as r,c as e,a2 as i}from"./chunks/framework.CHeM0PsO.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"arsitektur/mesin-analisis.md","filePath":"arsitektur/mesin-analisis.md","lastUpdated":1784467494000}'),n={name:"arsitektur/mesin-analisis.md"};function d(o,a,s,l,h,u){return r(),e("div",null,[...a[0]||(a[0]=[i('<h2 id="bab-10-mesin-analisis-—-parameter-threshold-formula" tabindex="-1">BAB 10: MESIN ANALISIS — PARAMETER, THRESHOLD &amp; FORMULA <a class="header-anchor" href="#bab-10-mesin-analisis-—-parameter-threshold-formula" aria-label="Permalink to &quot;BAB 10: MESIN ANALISIS — PARAMETER, THRESHOLD &amp; FORMULA&quot;">​</a></h2><h3 id="_10-1-skor-operasional-kotak-utama-tab-1" tabindex="-1">10.1 Skor Operasional (Kotak Utama Tab 1) <a class="header-anchor" href="#_10-1-skor-operasional-kotak-utama-tab-1" aria-label="Permalink to &quot;10.1 Skor Operasional (Kotak Utama Tab 1)&quot;">​</a></h3><p><strong>Formula:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skor = (Pencapaian_Target% × 0.5) + (Skor_Kebersihan% × 0.3) + (Kepatuhan_SOP% × 0.2)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Skor</th><th>Label</th><th>Warna</th></tr></thead><tbody><tr><td>≥ 85</td><td>EXCELLENT</td><td>Hijau</td></tr><tr><td>70 – 84</td><td>GOOD</td><td>Biru</td></tr><tr><td>50 – 69</td><td>ATTENTION</td><td>Kuning</td></tr><tr><td>&lt; 50</td><td>CRITICAL</td><td>Merah</td></tr></tbody></table><p><strong>Penjelasan:</strong> Skor ini menggabungkan 3 pilar utama operasional. Bobot terbesar (50%) ada di pencapaian target omset, karena pada akhirnya kafe harus menghasilkan uang. Kebersihan (30%) di posisi kedua karena langsung mempengaruhi pengalaman pelanggan. Kepatuhan SOP (20%) di posisi terakhir karena bersifat jangka panjang.</p><h3 id="_10-2-bar-persentase-pencapaian-target" tabindex="-1">10.2 Bar Persentase Pencapaian Target <a class="header-anchor" href="#_10-2-bar-persentase-pencapaian-target" aria-label="Permalink to &quot;10.2 Bar Persentase Pencapaian Target&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Persentase</th><th>Warna Bar</th></tr></thead><tbody><tr><td>≥ 100%</td><td>Hijau</td></tr><tr><td>80% – 99%</td><td>Oranye</td></tr><tr><td>&lt; 80%</td><td>Merah</td></tr></tbody></table><p><strong>Formula:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Persentase = (Total_Omset_Aktual ÷ Target_Omset_Proporsional) × 100%</span></span></code></pre></div><blockquote><p><strong>&quot;Target Proporsional&quot; — apa artinya?</strong> Jika target bulanan Anda Rp 180.000.000 dan bulan ini 30 hari, maka target harian = Rp 6.000.000. Jika Anda memilih rentang 7 hari di dashboard, maka target proporsional = 7 × Rp 6.000.000 = Rp 42.000.000. Ini mencegah perbandingan yang tidak adil.</p></blockquote><h3 id="_10-3-ai-predictive-summary-4-algoritma-utama" tabindex="-1">10.3 AI Predictive Summary (4 Algoritma Utama) <a class="header-anchor" href="#_10-3-ai-predictive-summary-4-algoritma-utama" aria-label="Permalink to &quot;10.3 AI Predictive Summary (4 Algoritma Utama)&quot;">​</a></h3><p>Kotak AI Summary di bagian atas Dashboard dihasilkan oleh 4 algoritma yang berjalan berurutan. Jika satu algoritma &quot;menang&quot; (kondisinya terpenuhi), ia akan menimpa algoritma di bawahnya:</p><h4 id="algoritma-1-fatigue-limit-batas-kelelahan-tim" tabindex="-1">Algoritma 1: Fatigue Limit (Batas Kelelahan Tim) <a class="header-anchor" href="#algoritma-1-fatigue-limit-batas-kelelahan-tim" aria-label="Permalink to &quot;Algoritma 1: Fatigue Limit (Batas Kelelahan Tim)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Kondisi</th><th>Putusan</th></tr></thead><tbody><tr><td>Rata-rata struk harian &gt; 100 <strong>DAN</strong> Skor Kebersihan &lt; 80%</td><td><strong>MERAH</strong> — &quot;Batas Kelelahan Tim tercapai. Tim butuh bantuan staf Part-Time!&quot;</td></tr><tr><td>Rata-rata struk harian &gt; 100 <strong>DAN</strong> Komplain &gt; 2× jumlah hari</td><td><strong>KUNING</strong> — &quot;Transaksi tinggi mengorbankan kualitas&quot;</td></tr></tbody></table><p><strong>Logika:</strong> Jika kafe sangat ramai (&gt;100 struk/hari) tapi kebersihan hancur, artinya staf kelelahan melayani pelanggan dan tidak sempat membersihkan kafe.</p><h4 id="algoritma-2-cuaca-×-kebersihan" tabindex="-1">Algoritma 2: Cuaca × Kebersihan <a class="header-anchor" href="#algoritma-2-cuaca-×-kebersihan" aria-label="Permalink to &quot;Algoritma 2: Cuaca × Kebersihan&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Kondisi</th><th>Putusan</th></tr></thead><tbody><tr><td>Hari hujan ≥ 30% dari total hari <strong>DAN</strong> Kebersihan &lt; 80%</td><td><strong>KUNING</strong> — &quot;Fasilitas rentan cuaca ekstrem. Terapkan SOP Double-Mopping!&quot;</td></tr></tbody></table><p><strong>Logika:</strong> Hujan deras menyebabkan lantai basah dan kotor. Jika kebersihan tetap buruk saat hujan, artinya tim tidak punya SOP cuaca buruk.</p><h4 id="algoritma-3-burnout-prediksi-resign" tabindex="-1">Algoritma 3: Burnout / Prediksi Resign <a class="header-anchor" href="#algoritma-3-burnout-prediksi-resign" aria-label="Permalink to &quot;Algoritma 3: Burnout / Prediksi Resign&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Kondisi</th><th>Putusan</th></tr></thead><tbody><tr><td>Rentang ≥ 7 hari <strong>DAN</strong> Rasio keterlambatan per hari &gt; 30%</td><td><strong>MERAH</strong> — &quot;Prediksi Churn: Waspada staf resign mendadak&quot;</td></tr></tbody></table><p><strong>Logika:</strong> Keterlambatan tinggi secara konsisten adalah sinyal demotivasi. Staf yang sering telat berpotensi keluar tanpa peringatan.</p><h4 id="algoritma-4-deteksi-anomali-kasir-petty-fraud" tabindex="-1">Algoritma 4: Deteksi Anomali Kasir (Petty Fraud) <a class="header-anchor" href="#algoritma-4-deteksi-anomali-kasir-petty-fraud" aria-label="Permalink to &quot;Algoritma 4: Deteksi Anomali Kasir (Petty Fraud)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Nilai</th></tr></thead><tbody><tr><td>Toleransi selisih kas wajar</td><td>Rp 2.000 (di bawah ini diabaikan)</td></tr><tr><td>Threshold total minus untuk aktifkan analisis</td><td>Rp 50.000</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Kondisi</th><th>Putusan</th></tr></thead><tbody><tr><td>Total selisih minus ≥ Rp 50.000 dalam periode</td><td>Sistem menghitung <strong>frekuensi kehadiran</strong> setiap staf pada hari-hari terjadinya minus, lalu menampilkan nama dengan frekuensi tertinggi</td></tr></tbody></table><p><strong>Logika:</strong> Sistem <strong>TIDAK menuduh</strong> satu orang secara langsung. Ia hanya mengatakan: &quot;Total minus Rp 200.000. Terjadi saat Amel bertugas 26 kali, Eko 17 kali.&quot; Keputusan akhir tetap di tangan Anda sebagai owner.</p><h4 id="fallback-jika-tidak-ada-algoritma-yang-terpicu" tabindex="-1">Fallback (Jika Tidak Ada Algoritma yang Terpicu) <a class="header-anchor" href="#fallback-jika-tidak-ada-algoritma-yang-terpicu" aria-label="Permalink to &quot;Fallback (Jika Tidak Ada Algoritma yang Terpicu)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Durasi</th><th>Kondisi</th><th>Putusan</th></tr></thead><tbody><tr><td>≤ 2 hari</td><td>Ada Event + Tanggal Tua (15-24)</td><td>Kuning: &quot;Trafik padat, daya beli rendah&quot;</td></tr><tr><td>≤ 2 hari</td><td>Ada Event + Tanggal Muda (25-5)</td><td>Hijau: &quot;Momen Emas&quot;</td></tr><tr><td>3-14 hari</td><td>Omset ≥ target DAN Kebersihan ≥ 90%</td><td>Hijau: &quot;Momentum Positif&quot;</td></tr><tr><td>&gt; 14 hari</td><td>Omset ≥ target DAN Kebersihan ≥ 95% DAN Komplain rendah</td><td>Hijau: &quot;Golden Era&quot;</td></tr><tr><td>&gt; 14 hari</td><td>Omset &lt; 90% target</td><td>Merah: &quot;Kegagalan Target Periode&quot;</td></tr></tbody></table><blockquote><p><strong>Catatan Tanggal:</strong> &quot;Tanggal Muda&quot; artinya dekat dengan tanggal gajian (akhir bulan/awal bulan: tanggal 25-5), sehingga daya beli masyarakat tinggi. &quot;Tanggal Tua&quot; (15-24) artinya uang sudah menipis.</p></blockquote><h3 id="_10-4-marketing-intelligence-5-modul-analisis" tabindex="-1">10.4 Marketing Intelligence (5 Modul Analisis) <a class="header-anchor" href="#_10-4-marketing-intelligence-5-modul-analisis" aria-label="Permalink to &quot;10.4 Marketing Intelligence (5 Modul Analisis)&quot;">​</a></h3><h4 id="modul-c1-tren-omset" tabindex="-1">Modul C1: Tren Omset <a class="header-anchor" href="#modul-c1-tren-omset" aria-label="Permalink to &quot;Modul C1: Tren Omset&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Perubahan vs Periode Sebelumnya</th><th>Status</th><th>Warna</th></tr></thead><tbody><tr><td>Naik ≥ 5%</td><td>Sehat</td><td>Hijau</td></tr><tr><td>Antara -5% sampai +5%</td><td>Stagnan</td><td>Kuning</td></tr><tr><td>Turun ≤ -5%</td><td>Kritis</td><td>Merah</td></tr></tbody></table><p><strong>Formula:</strong> <code>Perubahan% = ((Rata-rata_Harian_Periode_Ini - Rata-rata_Harian_Periode_Lalu) ÷ Rata-rata_Harian_Periode_Lalu) × 100%</code></p><h4 id="modul-c2-analisis-menu-hero-vs-dead" tabindex="-1">Modul C2: Analisis Menu (Hero vs Dead) <a class="header-anchor" href="#modul-c2-analisis-menu-hero-vs-dead" aria-label="Permalink to &quot;Modul C2: Analisis Menu (Hero vs Dead)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Parameter</th><th>Nilai</th></tr></thead><tbody><tr><td>Threshold konsistensi</td><td>Produk harus muncul di posisi Top/Bottom minimal <strong>40% dari total hari</strong> data</td></tr></tbody></table><p>Momentum produk juga dianalisis:</p><ul><li><strong>Rising Star:</strong> Produk yang makin sering muncul di Top di paruh kedua periode</li><li><strong>Fading:</strong> Produk hero yang mulai menurun</li><li><strong>Worse:</strong> Produk dead yang makin sering muncul</li><li><strong>Improving:</strong> Produk dead yang mulai membaik</li></ul><h4 id="modul-c3-korelasi-kebersihan-×-omset" tabindex="-1">Modul C3: Korelasi Kebersihan × Omset <a class="header-anchor" href="#modul-c3-korelasi-kebersihan-×-omset" aria-label="Permalink to &quot;Modul C3: Korelasi Kebersihan × Omset&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Kombinasi</th><th>Label</th><th>Artinya</th></tr></thead><tbody><tr><td>Omset ≥ 90% target, Kebersihan &lt; 70%</td><td><strong>The Perfect Storm</strong></td><td>Ramai tapi kotor — sangat berbahaya</td></tr><tr><td>Omset &lt; 70% target, Kebersihan &lt; 70%</td><td><strong>The Lazy Shift</strong></td><td>Sepi dan kotor — tim malas</td></tr><tr><td>Omset ≥ 85% target, Kebersihan ≥ 90%</td><td><strong>The Good Standard</strong></td><td>Performa ideal</td></tr><tr><td>Kebersihan &lt; 80% (umumnya)</td><td><strong>Hygiene di Bawah Standar</strong></td><td>Risiko komplain meningkat</td></tr></tbody></table><h4 id="modul-c4-sdm-risiko-operasional" tabindex="-1">Modul C4: SDM &amp; Risiko Operasional <a class="header-anchor" href="#modul-c4-sdm-risiko-operasional" aria-label="Permalink to &quot;Modul C4: SDM &amp; Risiko Operasional&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Tingkat Keterlambatan</th><th>Status</th><th>Tindakan</th></tr></thead><tbody><tr><td>&gt; 15%</td><td><strong>Krisis</strong> (Merah)</td><td>Pertimbangkan SP</td></tr><tr><td>5% – 15%</td><td><strong>Warning</strong> (Kuning)</td><td>SPV wajib briefing</td></tr><tr><td>&lt; 5%</td><td><strong>Positif</strong> (Hijau)</td><td>Beri apresiasi</td></tr></tbody></table><h4 id="modul-c5-benchmarking-ats" tabindex="-1">Modul C5: Benchmarking ATS <a class="header-anchor" href="#modul-c5-benchmarking-ats" aria-label="Permalink to &quot;Modul C5: Benchmarking ATS&quot;">​</a></h4><table tabindex="0"><thead><tr><th>ATS Aktual vs Benchmark</th><th>Status</th></tr></thead><tbody><tr><td>&lt; 80% dari benchmark</td><td><strong>Kritis</strong> — Gagal cross-selling</td></tr><tr><td>80% – 99% dari benchmark</td><td><strong>Warning</strong> — Masih di bawah standar</td></tr><tr><td>≥ 100% dari benchmark</td><td><strong>Positif</strong> — Upselling berhasil</td></tr></tbody></table><p><strong>Formula ATS:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Average Ticket Size (ATS) = Total Omset ÷ Total Transaksi (Struk)</span></span></code></pre></div><h3 id="_10-5-area-kritis-kebersihan" tabindex="-1">10.5 Area Kritis Kebersihan <a class="header-anchor" href="#_10-5-area-kritis-kebersihan" aria-label="Permalink to &quot;10.5 Area Kritis Kebersihan&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Threshold</th><th>Tindakan</th></tr></thead><tbody><tr><td>Rata-rata skor area &lt; 95%</td><td>Muncul di daftar &quot;Area Kritis&quot; dengan warna merah</td></tr></tbody></table><p>Sistem menampilkan maksimal 3 area terburuk, diurutkan dari skor terendah.</p><h3 id="_10-6-kpi-komplain" tabindex="-1">10.6 KPI Komplain <a class="header-anchor" href="#_10-6-kpi-komplain" aria-label="Permalink to &quot;10.6 KPI Komplain&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Total Komplain Sebulan</th><th>Label</th></tr></thead><tbody><tr><td>0</td><td>Aman (Hijau)</td></tr><tr><td>1</td><td>Waspada (Kuning)</td></tr><tr><td>2</td><td>Batas Maksimal (Oranye)</td></tr><tr><td>&gt; 2</td><td><strong>KPI Dilanggar</strong> (Merah)</td></tr></tbody></table><h3 id="_10-7-kpi-turnover" tabindex="-1">10.7 KPI Turnover <a class="header-anchor" href="#_10-7-kpi-turnover" aria-label="Permalink to &quot;10.7 KPI Turnover&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Total Resign per Kuartal (3 bulan)</th><th>Label</th></tr></thead><tbody><tr><td>0</td><td>Aman</td></tr><tr><td>1</td><td>Batas Maksimal</td></tr><tr><td>&gt; 1</td><td><strong>Risiko Kritis</strong></td></tr></tbody></table><h3 id="_10-8-pengaturan-gm-hanya-untuk-owner" tabindex="-1">10.8 Pengaturan GM (Hanya untuk Owner) <a class="header-anchor" href="#_10-8-pengaturan-gm-hanya-untuk-owner" aria-label="Permalink to &quot;10.8 Pengaturan GM (Hanya untuk Owner)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pengaturan</th><th>Lokasi</th><th>Fungsi</th></tr></thead><tbody><tr><td><strong>Target Tahunan</strong></td><td>Pengaturan GM di Dashboard</td><td>Digunakan untuk menghitung YTD Trajectory</td></tr><tr><td><strong>Benchmark ATS</strong></td><td>Di bawah tombol &quot;Simpan &amp; Tarik Analisis&quot;</td><td>Default Rp 30.000. Saran: gunakan harga kopi signature + 1 pastry</td></tr><tr><td><strong>Folder Google Drive</strong></td><td>Pengaturan GM di Dashboard</td><td>Mengubah folder utama penyimpanan file</td></tr></tbody></table><hr>',55)])])}const b=t(n,[["render",d]]);export{m as __pageData,b as default};
